import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Client-side encryption core","description":"","frontmatter":{"rfc":48,"title":"Client-side encryption core","status":"Implemented","date":"July 2026","author":"kasunben","scope":"packages/sdk, packages/manifest, runtime, packages/db, docs; builds on RFC 0008, RFC 0044, RFC 0052","incorporated_into_plan":"Yes - epic task 8.9"},"headers":[],"relativePath":"rfcs/0060-client-side-encryption-core.md","filePath":"rfcs/0060-client-side-encryption-core.md"}'),o={name:"rfcs/0060-client-side-encryption-core.md"};function n(s,e,l,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[i(`<h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Define a core client-side encryption capability for Sovereign so plugins can store sensitive user data that the runtime, operator, and server-side plugin code cannot decrypt. The first motivating consumer is Sovereign Wallet, but the capability is platform-level: any approved plugin should be able to use the same key-management and encrypted-object patterns.</p><p>This RFC makes Tier 4 from RFC 0008 concrete. Server-held at-rest and field-level encryption remain useful, but they do not protect against a compromised operator or server process. Client-side encryption does: plaintext is encrypted in the browser before upload and decrypted in the browser after download.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Some Sovereign data is too sensitive for a server-readable model. Passport and ID-document images, recovery codes, high-value personal records, and similar assets should remain private even if an operator account, VPS snapshot, database, or runtime process is compromised.</p><p>The wrong implementation path is for each plugin to invent its own crypto. That would create inconsistent recovery behavior, weak metadata practices, and plugin-specific APIs that are hard to audit. Sovereign should provide one core client-side encryption model and make sensitive plugins consume it through a stable SDK boundary.</p><h2 id="threat-model" tabindex="-1">Threat model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat model&quot;">​</a></h2><p>In scope:</p><ul><li>compromised or curious operator;</li><li>compromised server process or runtime route;</li><li>leaked database dump;</li><li>leaked storage volume or object-store bucket;</li><li>leaked backup/export bundle;</li><li>compromised server-side plugin code.</li></ul><p>Out of scope for this RFC:</p><ul><li>compromised client device after unlock;</li><li>malicious browser extensions reading the page;</li><li>phishing that captures the user&#39;s recovery secret;</li><li>server-side indexing, OCR, thumbnailing, or email rendering of encrypted plaintext.</li></ul><p>Client-side encryption changes the product contract. If the user loses every enrolled device and their recovery secret, encrypted data is unrecoverable.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>RFC 0008 charts zero-knowledge/E2EE as Tier 4, but does not specify the API or key model.</li><li>RFC 0044 defines plugin file storage and says bytes can live outside the DB.</li><li>RFC 0052 defines portability hooks that can include storage objects.</li><li><code>sdk.crypto</code> is reserved for server-side field encryption, where the runtime can decrypt.</li><li>No core SDK surface exists for client-side encryption.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="separate-server-side-crypto-from-client-side-crypto" tabindex="-1">Separate server-side crypto from client-side crypto <a class="header-anchor" href="#separate-server-side-crypto-from-client-side-crypto" aria-label="Permalink to &quot;Separate server-side crypto from client-side crypto&quot;">​</a></h3><p>Sovereign should keep two distinct concepts:</p><table tabindex="0"><thead><tr><th>Capability</th><th>Runtime can decrypt?</th><th>Primary purpose</th></tr></thead><tbody><tr><td>Server-side at-rest / field crypto</td><td>Yes</td><td>Protect disk/backups; runtime-mediated fields</td></tr><tr><td>Client-side encryption</td><td>No</td><td>Protect data from operator/server compromise</td></tr></tbody></table><p>The server-side, runtime-can-decrypt row spans two distinct mechanisms, both orthogonal to this RFC: whole-file SQLite at-rest encryption (<a href="./0071-sqlite-at-rest-encryption.html">RFC 0071</a>, opt-in) and field-level <code>sdk.crypto</code> (<a href="./0008-security-encryption-architecture.html">RFC 0008</a> Tier 3). This RFC&#39;s client-side encryption is the only tier the runtime <strong>cannot</strong> decrypt; a plugin may use both (e.g. Wallet stores ID images client-encrypted while the instance also runs SQLite at-rest), and they do not overlap or conflict.</p><p>The SDK names must make this distinction obvious. The exact final shape is an implementation decision, but this RFC assumes a separate client-side namespace such as:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.crypto.client;</span></span></code></pre></div><p>or an equivalent <code>sdk.e2ee</code> surface. It must not be confused with <code>sdk.crypto.encryptField()</code>, which is server-mediated field encryption from RFC 0008.</p><h3 id="key-hierarchy" tabindex="-1">Key hierarchy <a class="header-anchor" href="#key-hierarchy" aria-label="Permalink to &quot;Key hierarchy&quot;">​</a></h3><p>Each user has a client-side encryption profile:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Recovery secret / enrolled device secret</span></span>
<span class="line"><span>  -&gt; unlocks Client Master Key (CMK)</span></span>
<span class="line"><span>       -&gt; wraps Data Encryption Keys (DEKs)</span></span>
<span class="line"><span>            -&gt; encrypt objects and encrypted metadata</span></span></code></pre></div><p>Recommended primitives:</p><ul><li>random 256-bit Client Master Key generated in the browser;</li><li>random per-object DEK for each encrypted object or document;</li><li>AES-GCM for content encryption using WebCrypto;</li><li>HKDF for contextual subkeys where needed;</li><li>Argon2id or PBKDF2-derived key only for recovery-secret wrapping, depending on browser/runtime support and implementation constraints;</li><li>explicit algorithm/version metadata stored with each encrypted object.</li></ul><p>The server stores only wrapped keys, ciphertext, non-sensitive routing metadata, and audit/export/deletion metadata. The server never receives plaintext CMKs, DEKs, document bytes, or decrypted metadata.</p><h3 id="recovery-and-device-enrollment" tabindex="-1">Recovery and device enrollment <a class="header-anchor" href="#recovery-and-device-enrollment" aria-label="Permalink to &quot;Recovery and device enrollment&quot;">​</a></h3><p>Phase 1 supports two recovery paths:</p><ol><li><strong>Recovery secret:</strong> user records a generated recovery phrase or passphrase during encryption setup. The recovery secret wraps the CMK.</li><li><strong>Device enrollment:</strong> an already-unlocked device can enroll another device by wrapping the CMK for the new device.</li></ol><p>Operator escrow is rejected as a default because the threat model assumes operators can be compromised. A future enterprise policy may add escrow as an explicit, visible, opt-in mode, but it must not be the default.</p><p>Password reset does not recover client-side encrypted data. The UX must state this plainly before enabling encryption.</p><h3 id="encrypted-objects" tabindex="-1">Encrypted objects <a class="header-anchor" href="#encrypted-objects" aria-label="Permalink to &quot;Encrypted objects&quot;">​</a></h3><p>Large encrypted payloads should be stored as binary ciphertext through <code>sdk.storage</code> or the storage backend from RFC 0044. Do not Base64-encode images for DB storage by default.</p><p>Metadata is split:</p><ul><li><strong>plaintext routing metadata:</strong> object ID, owner user ID, plugin ID, storage key, created/updated timestamps, encryption version;</li><li><strong>encrypted metadata:</strong> human-readable title, document type, loyalty card name, issuing country, document number, original filename, notes, thumbnail metadata.</li></ul><p>Plugins may keep a small plaintext <code>kind_hint</code> only when it is essential for navigation, such as <code>card</code> versus <code>document</code>. Sensitive values should default to encrypted metadata.</p><h3 id="sdk-responsibilities" tabindex="-1">SDK responsibilities <a class="header-anchor" href="#sdk-responsibilities" aria-label="Permalink to &quot;SDK responsibilities&quot;">​</a></h3><p>The client-side crypto SDK should provide helpers for:</p><ul><li>checking whether encryption is set up for the current user;</li><li>creating a new encryption profile;</li><li>unlocking the CMK with a recovery secret or device key;</li><li>wrapping/unwrapping object DEKs;</li><li>encrypting/decrypting <code>Blob</code>, <code>ArrayBuffer</code>, and JSON metadata;</li><li>returning normalized unsupported/locked/error states;</li><li>exposing algorithm/version metadata for portability.</li></ul><p>The SDK should not hide the recovery model. Plugins must be able to detect locked state and show UX that asks the user to unlock encrypted data.</p><h3 id="platform-responsibilities" tabindex="-1">Platform responsibilities <a class="header-anchor" href="#platform-responsibilities" aria-label="Permalink to &quot;Platform responsibilities&quot;">​</a></h3><p>The platform owns:</p><ul><li>encrypted profile metadata tables;</li><li>wrapped CMK and device enrollment records;</li><li>optional recovery-secret wrapper metadata;</li><li>storage of encrypted object metadata needed for export/delete;</li><li>manifest permission and capability gating;</li><li>Account UX for setup, recovery warning, device enrollment, and recovery-secret rotation where appropriate.</li></ul><p>The platform does not own plugin-specific plaintext fields. Plugins decide what to encrypt, but the SDK makes the safe path straightforward.</p><h3 id="plugin-responsibilities" tabindex="-1">Plugin responsibilities <a class="header-anchor" href="#plugin-responsibilities" aria-label="Permalink to &quot;Plugin responsibilities&quot;">​</a></h3><p>Plugins using client-side encryption must:</p><ul><li>encrypt sensitive bytes and sensitive metadata before upload;</li><li>avoid sending plaintext to server actions, route handlers, logs, or analytics;</li><li>treat server-side processing of encrypted data as impossible unless the user explicitly decrypts locally;</li><li>implement locked-state UX;</li><li>participate in export/delete through RFC 0052 hooks;</li><li>document recovery implications.</li></ul><h2 id="wallet-as-first-consumer" tabindex="-1">Wallet as first consumer <a class="header-anchor" href="#wallet-as-first-consumer" aria-label="Permalink to &quot;Wallet as first consumer&quot;">​</a></h2><p>Sovereign Wallet should be the first real consumer of this core capability. It has a clear need: ID/passport images and sensitive card metadata should not be readable by the operator or runtime.</p><p>Wallet must not implement a one-off crypto system. If the core client-side encryption model is not ready, Wallet can ship only non-sensitive private cards or must remain blocked for sensitive documents.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="core-user-keypair-in-the-platform-user-model" tabindex="-1">Core user keypair in the platform user model <a class="header-anchor" href="#core-user-keypair-in-the-platform-user-model" aria-label="Permalink to &quot;Core user keypair in the platform user model&quot;">​</a></h3><p>Deferred. A public/private keypair is useful for sharing, multi-device key wrapping, and recovery contacts, but it is not required for single-user encrypted objects. Starting with a symmetric CMK plus device/recovery wrappers is simpler. A keypair can be added later without changing the object encryption model.</p><h3 id="store-encrypted-base64-images-in-the-database" tabindex="-1">Store encrypted Base64 images in the database <a class="header-anchor" href="#store-encrypted-base64-images-in-the-database" aria-label="Permalink to &quot;Store encrypted Base64 images in the database&quot;">​</a></h3><p>Rejected. Base64 adds size overhead and DB blobs make backup/migration behavior heavier. Encrypted binary bytes belong in the storage backend; metadata belongs in the DB.</p><h3 id="plugin-owned-custom-encryption" tabindex="-1">Plugin-owned custom encryption <a class="header-anchor" href="#plugin-owned-custom-encryption" aria-label="Permalink to &quot;Plugin-owned custom encryption&quot;">​</a></h3><p>Rejected. It is difficult to audit, gives inconsistent recovery UX, and creates future migration debt when a platform E2EE surface lands.</p><h3 id="operator-escrow-by-default" tabindex="-1">Operator escrow by default <a class="header-anchor" href="#operator-escrow-by-default" aria-label="Permalink to &quot;Operator escrow by default&quot;">​</a></h3><p>Rejected. It contradicts the threat model. If operators can be compromised, they must not hold default recovery material for client-side encrypted data.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Exact SDK namespace: <code>sdk.crypto.client</code>, <code>sdk.e2ee</code>, or another name.</li><li>Browser KDF choice and parameters for recovery-secret wrapping.</li><li>How to store device enrollment material across browsers and native shells.</li><li>Whether Account owns all setup/recovery UX or plugins can trigger scoped setup.</li><li>How much plaintext routing metadata is acceptable by default.</li><li>Whether sharing between users belongs in the first implementation or a later keypair-based phase.</li><li>How encrypted exports are packaged when the export bundle already has optional bundle encryption from RFC 0008.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Add manifest permission/capability for client-side encryption use.</li><li>Add encrypted profile metadata tables and SDK types.</li><li>Add Account setup/unlock/recovery-secret UX.</li><li>Add SDK helpers for encrypting/decrypting binary payloads and JSON metadata.</li><li>Integrate with <code>sdk.storage</code> for encrypted binary object storage.</li><li>Add export/delete behavior through RFC 0052 hooks.</li><li>Build Sovereign Wallet on top of the core surface.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.2</td><td>July 2026</td><td>Implemented (epic task 8.9), adoption steps 1–6: <code>sdk.e2ee</code> profile/recovery-wrapper/device-enrollment persistence, Account setup/unlock/recovery UX, CMK/DEK generation and wrap/unwrap, <code>Blob</code>/JSON object encryption (<code>e2ee-crypto</code>/<code>e2ee-object</code>/<code>e2ee-device</code>/<code>e2ee-state</code>), <code>sdk.storage</code> integration via its <code>metadata</code> field, and export/delete via <code>sdk.portability</code> (platform export includes wrapped ciphertext + metadata; account deletion removes it unconditionally). Step 7 (Wallet built on top of this core) is Sovereign Wallet&#39;s own separate roadmap, not part of this epic.</td></tr><tr><td>0.1</td><td>July 2026</td><td>Initial draft</td></tr></tbody></table>`,67)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
